```typescript
import React, { useState, useEffect, useRef, useMemo } from 'react';
import * as d3 from 'd3';
import * as topojson from 'topojson-client';
import { GlassPanel } from './GlassPanel';
import { Compass, Plus, Minus, RotateCcw, BarChart3, X, Database, Globe, Layers, Map as MapIcon, Loader2, Search } from 'lucide-react';
import { MapStyle, PALETTES, LabelSettings, TitleSettings, Annotation } from '../types';

// -- Types & Interfaces --

interface MapDataState {
  values: Record<string, number>;
  metric: string;
  unit: string;
}

interface Feature {
  type: 'Feature';
  id: string; // ISO 3166-1 numeric code
  properties: {
    name: string;
  };
  geometry: any;
}

interface MapPreviewProps {
  mapStyle: MapStyle;
  labelSettings: LabelSettings;
  titleSettings: TitleSettings;
  annotations: Annotation[];
  isAddingAnnotation: boolean;
  onAddAnnotation: (a: Annotation) => void;
  onUpdateAnnotation: (id: string, text: string) => void;
  onDeleteAnnotation: (id: string) => void;
  onMoveAnnotation: (id: string, x: number, y: number) => void;
}

// Sample Data Mapping (ISO 2-letter to Numeric ID for TopoJSON matching)
const ISO_MAPPING: Record<string, string> = {
  'US': '840', 'CA': '124', 'CN': '156', 'IN': '356', 
  'BR': '076', 'RU': '643', 'AU': '036', 'DE': '276',
  'FR': '250', 'GB': '826', 'ZA': '710', 'JP': '392',
  'GL': '304', 'SA': '682' 
};

const SAMPLE_DATASET = {
  metric: "Digital Infrastructure Index",
  unit: "Score",
  values: {
    '840': 95, '124': 88, '156': 92, '356': 65, '076': 58, '643': 60, 
    '036': 78, '276': 90, '250': 89, '826': 91, '392': 94, '710': 45, 
    '380': 82, '724': 80, '484': 70, '032': 68, '818': 55, '566': 48, 
    '360': 62, '792': 75, '682': 72, 
  }
};

type ProjectionType = 'mercator' | 'orthographic' | 'equalEarth';

export const MapPreview: React.FC<MapPreviewProps> = ({ 
  mapStyle, 
  labelSettings, 
  titleSettings,
  annotations,
  isAddingAnnotation,
  onAddAnnotation,
  onUpdateAnnotation,
  onDeleteAnnotation,
  onMoveAnnotation
}) => {
  // -- State --
  const [geoData, setGeoData] = useState<Feature[]>([]);
  const [loading, setLoading] = useState(true);
  const [projectionType, setProjectionType] = useState<ProjectionType>('mercator');
  const [searchQuery, setSearchQuery] = useState('');

  // D3 Selection State for imperative updates
  const svgRef = useRef<SVGSVGElement>(null);
  const gRef = useRef<SVGGElement>(null);

  // Data & Interaction State
  const [mapData, setMapData] = useState<MapDataState | null>(null);
  const [hoveredFeature, setHoveredFeature] = useState<Feature | null>(null);
  const [selectedFeatureId, setSelectedFeatureId] = useState<string | null>(null);
  const [tooltip, setTooltip] = useState({ visible: false, x: 0, y: 0, content: '' });

  // Annotation Editing State
  const [editingAnnotationId, setEditingAnnotationId] = useState<string | null>(null);
  const [draggingAnnotationId, setDraggingAnnotationId] = useState<string | null>(null);

  const containerRef = useRef<HTMLDivElement>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });
  const [currentZoom, setCurrentZoom] = useState(1);

  // -- Initialization --

  useEffect(() => {
    // Resize Observer
    if (containerRef.current) {
      const resizeObserver = new ResizeObserver((entries) => {
        if (entries[0]) {
          const { width, height } = entries[0].contentRect;
          setDimensions({ width, height });
        }
      });
      resizeObserver.observe(containerRef.current);
      return () => resizeObserver.disconnect();
    }
  }, []);

  useEffect(() => {
    // Fetch Map Data
    const fetchTopology = async () => {
      try {
        const response = await fetch('https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json');
        const topology = await response.json();
        // @ts-ignore
        const features = topojson.feature(topology, topology.objects.countries).features;
        setGeoData(features);
        setLoading(false);
      } catch (error) {
        console.error("Failed to load map data", error);
        setLoading(false);
      }
    };

    fetchTopology();
  }, []);

  // -- D3 Logic --

  // 1. Projection & Path Generator
  const { pathGenerator, projection, graticulePath } = useMemo(() => {
    let proj: d3.GeoProjection;

    const w = dimensions.width;
    const h = dimensions.height;

    switch (projectionType) {
      case 'orthographic':
        proj = d3.geoOrthographic()
          .fitExtent([[20, 20], [w - 20, h - 20]], { type: "Sphere" })
          .translate([w / 2, h / 2]);
        break;
      case 'equalEarth':
        proj = d3.geoEqualEarth()
          .fitExtent([[20, 20], [w - 20, h - 20]], { type: "Sphere" });
        break;
      case 'mercator':
      default:
        proj = d3.geoMercator()
          .fitExtent([[20, 20], [w - 20, h - 20]], { type: "Sphere" });
    }

    const pathGen = d3.geoPath().projection(proj);
    const graticuleGen = d3.geoGraticule10();

    return {
      projection: proj,
      pathGenerator: pathGen,
      graticulePath: pathGen(graticuleGen) || ''
    };
  }, [projectionType, dimensions]);

  // 2. Zoom Behavior
  useEffect(() => {
    if (!svgRef.current || !gRef.current) return;

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([1, 8])
      .on('zoom', (event) => {
        if (gRef.current) {
          d3.select(gRef.current).attr('transform', event.transform.toString());
          setCurrentZoom(event.transform.k);
        }
      });

    const svg = d3.select(svgRef.current);
    svg.call(zoom);

  }, [dimensions]); 

  // Helper: Get color scale
  const colorScale = useMemo(() => {
    if (!mapData) return null;
    const values = Object.values(mapData.values);
    const domain = d3.extent(values) as [number, number];
    const paletteColors = PALETTES[mapStyle.palette];
    const rangeColors = d3.quantize(d3.interpolateRgbBasis(paletteColors), mapStyle.classesCount);

    if (mapStyle.classificationMethod === 'quantile') {
      return d3.scaleQuantile<string>().domain(values).range(rangeColors);
    } else {
       return d3.scaleQuantile<string>().domain(values).range(rangeColors);
    }
  }, [mapData, mapStyle]);

  // -- Interaction Handlers --

  const handleZoomBtn = (factor: number) => {
    if (!svgRef.current) return;
    const svg = d3.select(svgRef.current);
    svg.transition().duration(300).call(
      // @ts-ignore
      d3.zoom().on("zoom", (e) => d3.select(gRef.current).attr("transform", e.transform)).scaleBy, 
      factor
    );
  };

  const resetView = () => {
    if (!svgRef.current) return;
    const svg = d3.select(svgRef.current);
    svg.transition().duration(750).call(
       // @ts-ignore
      d3.zoom().on("zoom", (e) => {
        d3.select(gRef.current).attr("transform", e.transform);
        setCurrentZoom(e.transform.k);
      }).transform, 
      d3.zoomIdentity
    );
    setSelectedFeatureId(null);
  };

  const handleCountryClick = (feature: Feature) => {
    if (isAddingAnnotation) return; // Prevent selection if adding annotation
    if (selectedFeatureId === feature.id) {
      resetView();
      setSelectedFeatureId(null);
    } else {
      setSelectedFeatureId(feature.id);

      const bounds = pathGenerator.bounds(feature);
      const dx = bounds[1][0] - bounds[0][0];
      const dy = bounds[1][1] - bounds[0][1];
      const x = (bounds[0][0] + bounds[1][0]) / 2;
      const y = (bounds[0][1] + bounds[1][1]) / 2;
      const scale = Math.max(1, Math.min(8, 0.9 / Math.max(dx / dimensions.width, dy / dimensions.height)));
      const translate = [dimensions.width / 2 - scale * x, dimensions.height / 2 - scale * y];

      if (svgRef.current) {
        d3.select(svgRef.current).transition().duration(750).call(
           // @ts-ignore
          d3.zoom().on("zoom", (e) => {
            d3.select(gRef.current).attr("transform", e.transform);
            setCurrentZoom(e.transform.k);
          }).transform, 
          d3.zoomIdentity.translate(translate[0], translate[1]).scale(scale)
        );
      }
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    const match = geoData.find(f => f.properties.name.toLowerCase().includes(searchQuery.toLowerCase()));
    if (match) {
      handleCountryClick(match);
      setSearchQuery('');
    }
  };

  const handleMapClick = (e: React.MouseEvent) => {
    if (isAddingAnnotation && svgRef.current) {
      const transform = d3.zoomTransform(svgRef.current);
      // Calculate coordinates relative to the SVG container
      const rect = svgRef.current.getBoundingClientRect();
      const clickX = e.clientX - rect.left;
      const clickY = e.clientY - rect.top;

      // Invert transform to get map-space coordinates
      const [x, y] = transform.invert([clickX, clickY]);

      onAddAnnotation({
        id: Date.now().toString(),
        x,
        y,
        text: 'New Annotation'
      });
    }
  };

  const handleAnnotationDrag = (e: React.MouseEvent, id: string) => {
     if (editingAnnotationId === id) return;
     e.stopPropagation();
     setDraggingAnnotationId(id);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
     if (draggingAnnotationId && svgRef.current) {
        const transform = d3.zoomTransform(svgRef.current);
        const rect = svgRef.current.getBoundingClientRect();
        const clickX = e.clientX - rect.left;
        const clickY = e.clientY - rect.top;
        const [x, y] = transform.invert([clickX, clickY]);
        onMoveAnnotation(draggingAnnotationId, x, y);
     }
  };

  const handleMouseUp = () => {
    setDraggingAnnotationId(null);
  };

  // -- Render Helpers --

  const getFill = (feature: Feature) => {
    if (selectedFeatureId === feature.id) return '#06b6d4'; 
    if (mapData && colorScale && mapData.values[feature.id] !== undefined) return colorScale(mapData.values[feature.id]);
    return '#1e293b';
  };

  const getOpacity = (feature: Feature) => {
    if (selectedFeatureId && selectedFeatureId !== feature.id) return 0.4;
    return 1;
  };

  return (
    <GlassPanel 
      className={`h-full w-full relative flex flex-col group overflow-hidden transition-colors duration-500 ${isAddingAnnotation ? 'cursor-crosshair' : ''}`}
      style={{ backgroundColor: mapStyle.backgroundColor }} 
    >

      {/* Title Overlay */}
      {titleSettings.position !== 'none' && (
        <div className={`
          absolute left-0 w-full p-6 pointer-events-none z-40 flex flex-col
          ${titleSettings.position === 'top' ? 'top-16' : 'bottom-24'}
