                        if (labelSettings.showOnHover && !isHovered && !isSelected) return null;

                        const centroid = pathGenerator.centroid(feature);
                        if (!centroid || isNaN(centroid[0])) return null;

                        // "Smart Labels" logic (basic collision/size check)
                        if (labelSettings.smartLabels) {
                           const area = pathGenerator.area(feature);
                           // Only show labels if country is large enough on screen
                           if (area * currentZoom < 400 && !isHovered) return null; 
                        }

                        // Don't show labels if zoomed out too far, unless smart labels is off
                        if (currentZoom < 2 && !labelSettings.smartLabels) return null;

                        return (
                          <text
                            key={`label-${feature.id}`}
                            x={centroid[0]}
