export const MapPreview: React.FC<MapPreviewProps> = ({ 
  mapStyle, 
  labelSettings, 
  titleSettings,
  annotations,
  isAddingAnnotation,
  onAddAnnotation,
  onUpdateAnnotation,
  onDeleteAnnotation,
