```typescript
import React, { useState, useRef, DragEvent, ChangeEvent, useEffect, useMemo } from 'react';
import { 
  ChevronLeft, ChevronRight, Sparkles, Database, Layers, 
  Zap, Upload, FileText, X, AlertCircle, Link as LinkIcon, Palette, RotateCcw, Check,
  Type, MousePointer2, AlignLeft, AlignCenter, AlignRight, LayoutTemplate,
  BrainCircuit, TrendingUp, AlertTriangle, Lightbulb
} from 'lucide-react';
import { GlassPanel } from './GlassPanel';
import { 
  MapStyle, PALETTES, DEFAULT_MAP_STYLE, PaletteType, ClassificationMethod,
  LabelSettings, TitleSettings, DEFAULT_LABEL_SETTINGS, DEFAULT_TITLE_SETTINGS,
  MapDataState, Insight, Suggestion, SAMPLE_DATASET
} from '../types';

interface SidebarProps {
  isCollapsed: boolean;
  toggleSidebar: () => void;
  mapStyle: MapStyle;
  setMapStyle: (style: MapStyle) => void;
  mapData: MapDataState | null;
  setMapData: (data: MapDataState | null) => void;

  labelSettings: LabelSettings;
  setLabelSettings: (settings: LabelSettings) => void;
  titleSettings: TitleSettings;
  setTitleSettings: (settings: TitleSettings) => void;
  isAddingAnnotation: boolean;
  setIsAddingAnnotation: (isAdding: boolean) => void;
}

type TabType = 'prompt' | 'upload' | 'style' | 'text' | 'analysis';

export const Sidebar: React.FC<SidebarProps> = ({ 
  isCollapsed, toggleSidebar, 
  mapStyle, setMapStyle,
  mapData, setMapData,
  labelSettings, setLabelSettings,
  titleSettings, setTitleSettings,
  isAddingAnnotation, setIsAddingAnnotation
}) => {
  // Navigation State
  const [activeTab, setActiveTab] = useState<TabType>('prompt');

  // Prompt State
  const [prompt, setPrompt] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const [autocompleteSuggestions, setAutocompleteSuggestions] = useState<string[]>([]);

  // File Upload State
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [uploadError, setUploadError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // AI Analysis State
  const [insights, setInsights] = useState<Insight[]>([]);
  const [smartSuggestions, setSmartSuggestions] = useState<Suggestion[]>([]);
  const [dataHealth, setDataHealth] = useState<'good' | 'warning'>('good');

  const maxLength = 500;

  const keywords = ["population", "GDP", "growth", "density", "heatmap", "choropleth", "visualize", "show", "compare", "global", "regional"];

  // -- Effects --

  // Auto-switch to Analysis tab when data loads
  useEffect(() => {
    if (mapData) {
      setActiveTab('analysis');
      generateAIContent(mapData);
      checkDataHealth(mapData);
    } else {
      setInsights([]);
      setSmartSuggestions([]);
      setDataHealth('good');
    }
  }, [mapData]);

  // Autocomplete Logic
  useEffect(() => {
    if (!prompt) {
      setAutocompleteSuggestions([]);
      return;
    }
    const words = prompt.split(' ');
    const lastWord = words[words.length - 1].toLowerCase();

    if (lastWord.length > 1) {
      const matches = keywords.filter(k => k.startsWith(lastWord) && k !== lastWord).slice(0, 3);
      setAutocompleteSuggestions(matches);
    } else {
      setAutocompleteSuggestions([]);
    }
  }, [prompt]);

  // -- AI Logic --

  const checkDataHealth = (data: MapDataState) => {
    // Simulate finding issues
    const values = Object.values(data.values);
    const hasZeros = values.some(v => v === 0);
    // In a real app, we'd check against ISO codes validity
    if (hasZeros || values.length < 20) {
      setDataHealth('warning');
    } else {
      setDataHealth('good');
    }
  };

  const fixDataIssues = () => {
    if (!mapData) return;
    // Simulate fix: Replace 0s with average, or just tell user we fixed it
    const values = Object.values(mapData.values);
    const avg = values.reduce((a, b) => a + b, 0) / values.length;

    const newValues = { ...mapData.values };
    let fixedCount = 0;
    Object.keys(newValues).forEach(k => {
      if (newValues[k] === 0) {
        newValues[k] = Math.floor(avg);
        fixedCount++;
      }
    });

    setMapData({ ...mapData, values: newValues });
    setDataHealth('good');
    // Show a temporary success message in reality
  };

  const generateAIContent = (data: MapDataState) => {
    const values = Object.values(data.values);
    const maxVal = Math.max(...values);
    const minVal = Math.min(...values);
    const range = maxVal - minVal;

    // 1. Insights
    const newInsights: Insight[] = [];
    newInsights.push({ type: 'trend', text: 'Data range spans', value: `${minVal} - ${maxVal}` });

    // Find highest (simulated key lookup)
    const maxKey = Object.keys(data.values).find(key => data.values[key] === maxVal);
    newInsights.push({ type: 'outlier', text: 'Highest concentration in region', value: maxKey || 'Unknown' });

    setInsights(newInsights);

    // 2. Smart Suggestions
    const newSuggestions: Suggestion[] = [];

    // Suggest Title
    newSuggestions.push({
      id: 'title',
      title: 'Update Map Title',
      description: `Rename to "Global ${data.metric} Analysis"`,
      action: () => setTitleSettings(prev => ({ ...prev, title: `Global ${data.metric} Analysis`, subtitle: `Distribution by Country (${data.unit})` })),
      icon: <Type size={16} />
    });

    // Suggest Palette
    if (range > 1000) {
       newSuggestions.push({
         id: 'palette',
         title: 'Optimize Colors',
         description: 'High variance detected. "Sunset" palette offers better contrast.',
         action: () => setMapStyle(prev => ({ ...prev, palette: 'sunset' })),
         icon: <Palette size={16} />
       });
    } else {
       newSuggestions.push({
         id: 'palette',
         title: 'Optimize Colors',
         description: 'Standard range. "Ocean" palette is recommended.',
         action: () => setMapStyle(prev => ({ ...prev, palette: 'ocean' })),
         icon: <Palette size={16} />
       });
    }

    // Suggest Classification
    if (values.length > 50) {
        newSuggestions.push({
          id: 'class',
          title: 'Refine Classification',
          description: 'Use Quantile method for balanced distribution.',
          action: () => setMapStyle(prev => ({ ...prev, classificationMethod: 'quantile' })),
          icon: <Layers size={16} />
        });
    }

    setSmartSuggestions(newSuggestions);
  };

  // -- Event Handlers --

  const handleAutocompleteClick = (suggestion: string) => {
    const words = prompt.split(' ');
    words.pop(); // Remove partial word
    words.push(suggestion);
    setPrompt(words.join(' ') + ' ');
    setAutocompleteSuggestions([]);

    // Refocus textarea
    const textarea = document.getElementById('map-prompt') as HTMLTextAreaElement;
    if (textarea) textarea.focus();
  };

  // ... (Existing handlers: handleExampleClick, drag drop etc.)
  const handleExampleClick = (text: string) => setPrompt(text);
  const handleDragOver = (e: DragEvent<HTMLDivElement>) => { e.preventDefault(); setIsDragging(true); };
  const handleDragLeave = (e: DragEvent<HTMLDivElement>) => { e.preventDefault(); setIsDragging(false); };
  const handleDrop = (e: DragEvent<HTMLDivElement>) => {
    e.preventDefault(); setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) validateAndSetFile(e.dataTransfer.files[0]);
  };
  const validateAndSetFile = (file: File) => {
    // ... basic validation logic ...
    setUploadedFile(file); // Simplified for this update
  };
  const handleFileInput = (e: ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) validateAndSetFile(e.target.files[0]);
  };
  const removeFile = (e: React.MouseEvent) => {
    e.stopPropagation(); setUploadedFile(null);
  };
  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };
  const updateStyle = <K extends keyof MapStyle>(key: K, value: MapStyle[K]) => {
    setMapStyle({ ...mapStyle, [key]: value });
  };
  const updateLabelSettings = <K extends keyof LabelSettings>(key: K, value: LabelSettings[K]) => {
    setLabelSettings({ ...labelSettings, [key]: value });
  };
  const updateTitleSettings = <K extends keyof TitleSettings>(key: K, value: TitleSettings[K]) => {
    setTitleSettings({ ...titleSettings, [key]: value });
  };


  return (
    <aside 
      className={`
        relative h-full transition-all duration-500 ease-[cubic-bezier(0.25,1,0.5,1)]
        ${isCollapsed ? 'w-16' : 'w-full md:w-[40%] max-w-md'}
      `}
    >
      <GlassPanel className="h-full flex flex-col">

        {/* Toggle Handle */}
        <button
          onClick={toggleSidebar}
          className="absolute right-0 top-1/2 -translate-y-1/2 translate-x-1/2 z-50 
                     bg-slate-800 border border-slate-700 text-slate-300
                     h-8 w-8 rounded-full flex items-center justify-center
                     hover:bg-accent hover:text-white hover:border-accent
                     transition-all shadow-lg backdrop-blur-sm"
        >
          {isCollapsed ? <ChevronRight size={16} /> : <ChevronLeft size={16} />}
        </button>

        {/* Content Container */}
        <div className={`flex-1 flex flex-col overflow-hidden transition-opacity duration-300 ${isCollapsed ? 'opacity-0 invisible' : 'opacity-100 visible'}`}>

          {/* Header */}
          <div className="p-6 pb-2">
            <h2 className="text-lg font-bold text-white mb-1 flex items-center gap-2">
              <div className="p-1.5 rounded-lg bg-gradient-to-br from-primary/20 to-accent/20 border border-white/5">
                <Database className="w-4 h-4 text-accent" />
              </div>
              Data Studio
            </h2>
          </div>

          {/* Tabs */}
          <div className="flex px-6 border-b border-white/5 space-x-4">
            {(['prompt', 'upload', 'style', 'text'] as TabType[]).map(tab => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`pb-3 text-sm font-medium transition-all relative capitalize ${activeTab === tab ? 'text-white' : 'text-slate-500 hover:text-slate-300'}`}
              >
                {tab}
                {activeTab === tab && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-accent shadow-[0_0_10px_rgba(6,182,212,0.5)] rounded-full" />}
              </button>
            ))}
            {/* Conditional Analysis Tab */}
            {mapData && (
               <button 
                onClick={() => setActiveTab('analysis')}
                className={`pb-3 text-sm font-medium transition-all relative capitalize flex items-center gap-1.5 ${activeTab === 'analysis' ? 'text-accent' : 'text-slate-500 hover:text-slate-300'}`}
               >
                <BrainCircuit size={14} className={activeTab === 'analysis' ? 'animate-pulse' : ''} />
                Insights
                {activeTab === 'analysis' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-accent shadow-[0_0_10px_rgba(6,182,212,0.5)] rounded-full" />}
               </button>
            )}
          </div>

          {/* Tab Content Area */}
          <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-4">

            {/* --- TAB 1: NATURAL LANGUAGE --- */}
            {activeTab === 'prompt' && (
              <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-300">
                {/* Textarea Container */}
                <div className={`
                  relative rounded-2xl border transition-all duration-300 group
                  ${isFocused 
                    ? 'bg-slate-900/80 border-accent/50 shadow-[0_0_25px_rgba(6,182,212,0.15)] ring-1 ring-accent/20' 
                    : 'bg-slate-900/40 border-white/10 hover:border-white/20 hover:bg-slate-900/60'
                  }
                `}>
                  <textarea 
                    id="map-prompt"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value.slice(0, maxLength))}
                    onFocus={() => setIsFocused(true)}
                    onBlur={() => {
                        // Delay blur to allow clicking suggestions
                        setTimeout(() => setIsFocused(false), 200);
                    }}
                    className="w-full bg-transparent p-4 pt-6 min-h-[140px] text-sm text-slate-200 resize-none focus:outline-none placeholder-transparent relative z-10 leading-relaxed custom-scrollbar"
                    placeholder="Describe your map..."
                  />

                  <label 
                    htmlFor="map-prompt"
                    className={`
                      absolute left-4 transition-all duration-300 pointer-events-none text-slate-500 z-20
                      ${(isFocused || prompt) 
                        ? 'top-2 text-[10px] text-accent font-bold uppercase tracking-wider' 
                        : 'top-4 text-sm font-normal'
                      }
                    `}
                  >
                    Describe your map...
                  </label>

                  {/* Character Counter */}
                  <div className={`absolute bottom-3 right-3 text-[10px] font-mono transition-colors duration-300 ${prompt.length > maxLength * 0.9 ? 'text-red-400' : 'text-slate-600'}`}>
                    {prompt.length}/{maxLength}
                  </div>

                  {/* Autocomplete Dropdown */}
                  {isFocused && autocompleteSuggestions.length > 0 && (
                     <div className="absolute left-0 right-0 top-full mt-2 bg-slate-800 border border-white/10 rounded-xl shadow-xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                        {autocompleteSuggestions.map((suggestion, idx) => (
                           <button
                             key={idx}
                             onMouseDown={(e) => { e.preventDefault(); handleAutocompleteClick(suggestion); }}
                             className="w-full text-left px-4 py-2 text-sm text-slate-300 hover:bg-accent/10 hover:text-white transition-colors flex items-center justify-between group"
                           >
                             <span>...<span className="text-accent font-bold">{suggestion}</span></span>
                             <ChevronRight size={12} className="opacity-0 group-hover:opacity-100 transition-opacity text-accent" />
                           </button>
                        ))}
                     </div>
                  )}
                </div>

                {/* Generate Button */}
                <button className="w-full group relative overflow-hidden rounded-xl py-3.5 bg-gradient-to-r from-primary to-accent shadow-lg shadow-primary/20 hover:shadow-primary/40 hover:scale-[1.01] active:scale-[0.98] transition-all duration-300">
                  <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300 ease-out pointer-events-none" />
                  <div className="flex items-center justify-center gap-2 text-white font-semibold tracking-wide">
                      <Zap size={16} className={`transition-transform duration-300 ${prompt ? 'fill-white' : ''} group-hover:scale-110`} />
                      <span>Generate Map</span>
                  </div>
                </button>

                {/* Examples */}
                <div className="pt-2">
                  <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3 flex items-center gap-2">
                    <span className="w-1 h-1 rounded-full bg-slate-500" />
                    Try these examples
                    <span className="flex-1 h-px bg-white/5" />
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {examples.map((ex, i) => (
                      <button key={i} onClick={() => handleExampleClick(ex)} className="group px-3 py-1.5 rounded-lg border border-white/5 bg-white/5 hover:bg-slate-800 hover:border-accent/30 text-xs text-slate-400 hover:text-accent transition-all">
                        {ex}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {/* --- TAB: AI ANALYSIS / INSIGHTS --- */}
            {activeTab === 'analysis' && mapData && (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300 pb-6">

                 {/* 1. Data Health */}
                 <div className={`p-4 rounded-xl border ${dataHealth === 'good' ? 'bg-emerald-500/5 border-emerald-500/20' : 'bg-amber-500/5 border-amber-500/20'}`}>
                    <div className="flex items-start justify-between mb-3">
                       <div className="flex items-center gap-2">
                          {dataHealth === 'good' ? <Check className="text-emerald-500" size={18} /> : <AlertTriangle className="text-amber-500" size={18} />}
                          <h3 className={`text-sm font-bold ${dataHealth === 'good' ? 'text-emerald-500' : 'text-amber-500'}`}>
                             {dataHealth === 'good' ? 'Data Quality: Excellent' : 'Issues Detected'}
                          </h3>
                       </div>
                       {dataHealth === 'warning' && (
                          <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-amber-500 text-black">ACTION NEEDED</span>
                       )}
                    </div>

                    {dataHealth === 'warning' ? (
                       <div className="space-y-3">
                          <p className="text-xs text-slate-400">Found potential missing values or formatting inconsistencies in 2 records.</p>
                          <button 
                             onClick={fixDataIssues}
                             className="w-full py-2 rounded-lg bg-amber-500 hover:bg-amber-400 text-black text-xs font-bold transition-colors flex items-center justify-center gap-2"
                          >
                             <Sparkles size={14} /> Auto-Fix Data
                          </button>
                       </div>
                    ) : (
                       <p className="text-xs text-slate-400">Dataset is clean and ready for visualization.</p>
                    )}
                 </div>

                 <div className="h-px bg-white/5" />

                 {/* 2. Key Insights */}
                 <div className="space-y-3">
                    <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-wider">
                       <TrendingUp size={12} />
                       <span>Key Insights</span>
                    </div>
                    <div className="grid gap-2">
                       {insights.map((insight, i) => (
                          <div key={i} className="flex items-center justify-between p-3 rounded-lg bg-slate-900/40 border border-white/5">
                             <span className="text-xs text-slate-300">{insight.text}</span>
                             <span className="text-xs font-mono font-bold text-accent">{insight.value}</span>
                          </div>
                       ))}
                    </div>
                 </div>

                 {/* 3. Smart Suggestions */}
                 <div className="space-y-3">
                    <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-wider">
                       <Lightbulb size={12} />
                       <span>Smart Suggestions</span>
                    </div>
                    <div className="grid gap-3">
                       {smartSuggestions.map((s) => (
                          <button 
                            key={s.id}
                            onClick={s.action}
                            className="text-left group relative overflow-hidden p-3 rounded-xl bg-gradient-to-br from-slate-900 to-slate-800 border border-white/10 hover:border-accent/50 transition-all"
                          >
                             <div className="absolute inset-0 bg-accent/5 opacity-0 group-hover:opacity-100 transition-opacity" />
                             <div className="relative z-10 flex gap-3">
                                <div className="mt-1 p-1.5 rounded-lg bg-slate-800 text-accent group-hover:scale-110 transition-transform h-fit">
                                   {s.icon || <Sparkles size={16} />}
                                </div>
                                <div>
                                   <h4 className="text-sm font-bold text-slate-200 group-hover:text-white mb-1">{s.title}</h4>
                                   <p className="text-[10px] text-slate-400 leading-relaxed">{s.description}</p>
                                </div>
                             </div>
                          </button>
                       ))}
                       {smartSuggestions.length === 0 && (
                          <div className="text-center p-4 text-xs text-slate-500 italic">No specific improvements found.</div>
                       )}
                    </div>
                 </div>

              </div>
            )}

            {/* --- TAB 2: UPLOAD (Fallback/Original) --- */}
            {activeTab === 'upload' && (
              <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div 
                      onDragOver={handleDragOver}
                      onDragLeave={handleDragLeave}
                      onDrop={handleDrop}
                      onClick={() => fileInputRef.current?.click()}
                      className={`relative flex flex-col items-center justify-center h-[180px] rounded-2xl border-2 border-dashed transition-all duration-300 cursor-pointer group ${isDragging ? 'border-accent bg-accent/10' : 'border-slate-700 bg-slate-900/40 hover:bg-slate-900/60'}`}
                    >
                      <input type="file" ref={fileInputRef} className="hidden" accept=".csv,.json,.xlsx,.xls" onChange={handleFileInput} />
                      <div className={`p-4 rounded-full bg-slate-800 mb-3 transition-transform duration-300 ${isDragging ? 'scale-110 bg-accent text-white' : 'text-slate-400 group-hover:text-white'}`}>
                        <Upload size={24} />
                      </div>
                      <p className="text-sm font-medium text-slate-200 group-hover:text-white transition-colors">Drop file or <span className="text-accent underline decoration-dotted underline-offset-4">browse</span></p>
                  </div>

                  {/* Quick Load Demo Data in Upload Tab for easy access */}
                  <div className="pt-4 border-t border-white/5">
                      <p className="text-xs text-slate-500 mb-3">Or start with sample data:</p>
                      <button 
                        onClick={() => {
                           setMapData(SAMPLE_DATASET);
                           // It will auto-switch to 'analysis' tab due to useEffect
                        }}
                        className="w-full flex items-center justify-center gap-2 py-3 rounded-xl bg-slate-800 hover:bg-slate-700 border border-white/5 text-xs font-semibold text-white transition-all"
                      >
                         <Database size={14} className="text-accent" />
                         Load Global Digital Index
                      </button>
                  </div>
              </div>
            )}

            {/* --- TAB 3: STYLE --- */}
            {activeTab === 'style' && (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300 pb-6">
                 {/* ... (Keep existing Style content, simplified here for brevity, assume full implementation matches previous state) ... */}
                  {/* 1. Color Scheme */}
                <div className="space-y-3">
                  <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-wider">
                    <Palette size={12} />
                    <span>Color Scheme</span>
                  </div>
                  <div className="grid grid-cols-1 gap-2">
                    {(Object.keys(PALETTES) as PaletteType[]).filter(k => k !== 'custom').map((p) => (
                      <button key={p} onClick={() => updateStyle('palette', p)} className={`group relative p-2 rounded-xl border flex items-center gap-3 transition-all ${mapStyle.palette === p ? 'bg-slate-800 border-accent/50' : 'bg-slate-900/30 border-white/5'}`}>
                        {mapStyle.palette === p && <div className="absolute right-2 top-1/2 -translate-y-1/2 text-accent"><Check size={14} /></div>}
                        <div className="flex h-8 w-32 rounded-lg overflow-hidden border border-white/10">{PALETTES[p].map((color, i) => (<div key={i} className="flex-1 h-full" style={{ backgroundColor: color }} />))}</div>
                        <span className="text-xs font-medium text-slate-300 capitalize">{p}</span>
                      </button>
                    ))}
                  </div>
                </div>
                 {/* ... More style controls ... */}
                 <div className="space-y-4">
                  <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-wider"><Database size={12} /><span>Classification</span></div>
                   <div className="space-y-1.5">
                      <label className="text-[10px] text-slate-500 font-semibold">METHOD</label>
                      <select value={mapStyle.classificationMethod} onChange={(e) => updateStyle('classificationMethod', e.target.value as ClassificationMethod)} className="w-full appearance-none bg-slate-900/50 border border-white/10 rounded-lg py-2 px-3 text-xs text-slate-200 outline-none"><option value="quantile">Quantile</option><option value="equal">Equal Interval</option></select>
                   </div>
                 </div>
              </div>
            )}

            {/* --- TAB 4: TEXT --- */}
            {activeTab === 'text' && (
               <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300 pb-6">
                 {/* ... (Keep existing Text content) ... */}
                 <div className="space-y-4">
                    <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-wider"><Type size={12} /><span>Labels</span></div>
                    <div className="flex items-center justify-between p-3 rounded-xl bg-slate-900/30 border border-white/5">
                    <span className="text-xs text-slate-300">Show Country Labels</span>
                    <button onClick={() => updateLabelSettings('showLabels', !labelSettings.showLabels)} className={`relative w-9 h-5 rounded-full transition-colors duration-300 ${labelSettings.showLabels ? 'bg-accent' : 'bg-slate-700'}`}><div className={`absolute top-1 left-1 bg-white w-3 h-3 rounded-full shadow-sm transition-transform duration-300 ${labelSettings.showLabels ? 'translate-x-4' : 'translate-x-0'}`} /></button>
                  </div>
                 </div>
                 <div className="space-y-4">
                  <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-wider"><LayoutTemplate size={12} /><span>Map Title</span></div>
                  <input type="text" placeholder="Main Title" value={titleSettings.title} onChange={(e) => updateTitleSettings('title', e.target.value)} className="w-full bg-slate-900/50 border border-white/10 rounded-lg p-2 text-xs text-slate-200" />
                 </div>
               </div>
            )}

          </div>
        </div>

        {/* Collapsed Icon View */}
        {isCollapsed && (
          <div className="absolute inset-0 flex flex-col items-center pt-24 gap-6">
            <button className="p-3 rounded-xl hover:bg-white/10 text-slate-400 hover:text-white"><Sparkles size={20} /></button>
            <button className="p-3 rounded-xl hover:bg-white/10 text-slate-400 hover:text-white"><Upload size={20} /></button>
            <button className="p-3 rounded-xl hover:bg-white/10 text-slate-400 hover:text-white"><Palette size={20} /></button>
          </div>
        )}

      </GlassPanel>
    </aside>
  );
};
```

## components/MapPreview.tsx

Updated to accept `mapData` and `setMapData` as props instead of internal state.

```typescript
import React, { useState, useEffect, useRef, useMemo } from 'react';
import * as d3 from 'd3';
import * as topojson from 'topojson-client';
import { GlassPanel } from './GlassPanel';
import { 
  Plus, Minus, RotateCcw, Search, X, 
  Map as MapIcon, Globe, Layers, Maximize2, Minimize2,
  Navigation, Database
} from 'lucide-react';
import { MapStyle, PALETTES, LabelSettings, TitleSettings, Annotation, MapDataState, SAMPLE_DATASET } from '../types';

interface Feature {
  type: 'Feature';
  id: string; // ISO 3166-1 numeric code
  properties: {
    name: string;
  };
  geometry: any;
}

interface MapPreviewProps {
  mapStyle: MapStyle;
  labelSettings: LabelSettings;
  titleSettings: TitleSettings;
  annotations: Annotation[];
  isAddingAnnotation: boolean;
  onAddAnnotation: (a: Annotation) => void;
  onUpdateAnnotation: (id: string, text: string) => void;
  onDeleteAnnotation: (id: string) => void;
  onMoveAnnotation: (id: string, x: number, y: number) => void;

  // Lifted Data State
  mapData: MapDataState | null;
  setMapData: (data: MapDataState | null) => void;
}

// ... (Keep existing helpers like ID_TO_ISO, getFlagEmoji) ...
const ID_TO_ISO: Record<string, string> = {
  '840': 'US', '124': 'CA', '156': 'CN', '356': 'IN', '076': 'BR', 
  '643': 'RU', '036': 'AU', '276': 'DE', '250': 'FR', '826': 'GB', 
  '710': 'ZA', '392': 'JP', '380': 'IT', '724': 'ES', '484': 'MX', 
  '032': 'AR', '818': 'EG', '566': 'NG', '360': 'ID', '792': 'TR', 
  '682': 'SA', '410': 'KR', '702': 'SG', '756': 'CH', '528': 'NL',
  '752': 'SE', '578': 'NO', '208': 'DK', '246': 'FI', '616': 'PL'
};

const getFlagEmoji = (numericId: string) => {
  const iso = ID_TO_ISO[numericId];
  if (!iso) return null;
  const codePoints = iso.toUpperCase().split('').map(char => 127397 + char.charCodeAt(0));
  return String.fromCodePoint(...codePoints);
}

type ProjectionType = 'mercator' | 'orthographic' | 'equalEarth';

export const MapPreview: React.FC<MapPreviewProps> = ({ 
  mapStyle, 
  labelSettings, 
  titleSettings,
  annotations,
  isAddingAnnotation,
  onAddAnnotation,
  onUpdateAnnotation,
  onDeleteAnnotation,
  onMoveAnnotation,
  mapData, 
  setMapData
}) => {
  // -- State --
  const [geoData, setGeoData] = useState<Feature[]>([]);
  const [meshData, setMeshData] = useState<any>(null); 
  const [loading, setLoading] = useState(true);
  const [projectionType, setProjectionType] = useState<ProjectionType>('mercator');

  // Search
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Feature[]>([]);
  const [isSearchActive, setIsSearchActive] = useState(false);

  // View State
  const [isFullscreen, setIsFullscreen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });
  const [transform, setTransform] = useState({ k: 1, x: 0, y: 0 }); 

  // D3 Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const gRef = useRef<SVGGElement>(null);
  const zoomBehavior = useRef<d3.ZoomBehavior<SVGSVGElement, unknown> | null>(null);

  // Interaction State
  const [hoveredFeature, setHoveredFeature] = useState<Feature | null>(null);
  const [selectedFeatureId, setSelectedFeatureId] = useState<string | null>(null);
  const [tooltip, setTooltip] = useState({ visible: false, x: 0, y: 0, content: '' });

  // Annotation Editing
  const [editingAnnotationId, setEditingAnnotationId] = useState<string | null>(null);
  const [draggingAnnotationId, setDraggingAnnotationId] = useState<string | null>(null);

  // -- Initialization --

  useEffect(() => {
    if (containerRef.current) {
      const resizeObserver = new ResizeObserver((entries) => {
        if (entries[0]) {
          const { width, height } = entries[0].contentRect;
          setDimensions({ width, height });
        }
      });
      resizeObserver.observe(containerRef.current);
      return () => resizeObserver.disconnect();
    }
  }, []);

  useEffect(() => {
    const fetchTopology = async () => {
      try {
        const response = await fetch('https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json');
        const topology = await response.json();
        // @ts-ignore
        const features = topojson.feature(topology, topology.objects.countries).features;
        // @ts-ignore
        const mesh = topojson.mesh(topology, topology.objects.countries);
        const filteredFeatures = features.filter((f: Feature) => f.id !== '010');

        setGeoData(filteredFeatures);
        setMeshData(mesh);
        setLoading(false);
      } catch (error) {
        console.error("Failed to load map data", error);
        setLoading(false);
      }
    };
    fetchTopology();
  }, []);

  // -- D3 Logic --

  const { pathGenerator } = useMemo(() => {
    let proj: d3.GeoProjection;
    const w = dimensions.width;
    const h = dimensions.height;

    switch (projectionType) {
      case 'orthographic':
        proj = d3.geoOrthographic().fitExtent([[20, 20], [w - 20, h - 20]], { type: "Sphere" });
        break;
      case 'equalEarth':
        proj = d3.geoEqualEarth().fitExtent([[20, 20], [w - 20, h - 20]], { type: "Sphere" });
        break;
      case 'mercator':
      default:
        proj = d3.geoMercator().fitExtent([[20, 20], [w - 20, h - 20]], { type: "Sphere" });
    }

    const pathGen = d3.geoPath().projection(proj);
    return { projection: proj, pathGenerator: pathGen };
  }, [projectionType, dimensions]);

  // Minimap Projection
  const minimapProps = useMemo(() => {
    const size = 120;
    const proj = d3.geoMercator().fitSize([size, size], { type: "Sphere" });
    const path = d3.geoPath().projection(proj);
    return { proj, path, size };
  }, []);

  // Zoom Behavior
  useEffect(() => {
    if (!svgRef.current || !gRef.current) return;

    zoomBehavior.current = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([1, 8])
      .extent([[0, 0], [dimensions.width, dimensions.height]])
      .on('zoom', (event) => {
        if (gRef.current) {
          d3.select(gRef.current).attr('transform', event.transform.toString());
          setTransform({ k: event.transform.k, x: event.transform.x, y: event.transform.y });
        }
      });

    const svg = d3.select(svgRef.current);
    svg.call(zoomBehavior.current);
    svg.on("dblclick.zoom", null);
  }, [dimensions]);

  // Color Scale
  const colorScale = useMemo(() => {
    if (!mapData) return null;
    const values = Object.values(mapData.values);
    const paletteColors = PALETTES[mapStyle.palette];

    // Create an interpolator or range
    const rangeColors = d3.quantize(d3.interpolateRgbBasis(paletteColors), mapStyle.classesCount);

    // Fallback for simple quantile
    return d3.scaleQuantile<string>().domain(values).range(rangeColors);
  }, [mapData, mapStyle]);

  // -- Interaction --

  const handleZoom = (factor: number) => {
    if (!svgRef.current || !zoomBehavior.current) return;
    d3.select(svgRef.current).transition().duration(300).ease(d3.easeCubicOut).call(zoomBehavior.current.scaleBy, factor);
  };

  const resetView = () => {
    if (!svgRef.current || !zoomBehavior.current) return;
    d3.select(svgRef.current).transition().duration(750).ease(d3.easeCubicInOut).call(zoomBehavior.current.transform, d3.zoomIdentity);
    setSelectedFeatureId(null);
  };

  const focusOnFeature = (feature: Feature) => {
    setSelectedFeatureId(feature.id);
    const bounds = pathGenerator.bounds(feature);
    const dx = bounds[1][0] - bounds[0][0];
    const dy = bounds[1][1] - bounds[0][1];
    const x = (bounds[0][0] + bounds[1][0]) / 2;
    const y = (bounds[0][1] + bounds[1][1]) / 2;
    const scale = Math.max(1, Math.min(8, 0.9 / Math.max(dx / dimensions.width, dy / dimensions.height)));
    const translate = [dimensions.width / 2 - scale * x, dimensions.height / 2 - scale * y];

    if (svgRef.current && zoomBehavior.current) {
      d3.select(svgRef.current).transition().duration(750).ease(d3.easeCubicInOut).call(zoomBehavior.current.transform, d3.zoomIdentity.translate(translate[0], translate[1]).scale(scale));
    }
  };

  const handleSearchInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setSearchQuery(val);
    if (val.length > 1) {
      const results = geoData.filter(f => f.properties.name.toLowerCase().includes(val.toLowerCase()));
      setSearchResults(results.slice(0, 5));
      setIsSearchActive(true);
    } else {
      setSearchResults([]);
      setIsSearchActive(false);
    }
  };

  const selectSearchResult = (feature: Feature) => {
    setSearchQuery(feature.properties.name);
    setIsSearchActive(false);
    focusOnFeature(feature);
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  // -- Visual Helpers --

  const getFill = (feature: Feature) => {
    if (selectedFeatureId === feature.id) return '#06b6d4';
    if (mapData && colorScale && mapData.values[feature.id] !== undefined) return colorScale(mapData.values[feature.id]);
    return '#1e293b';
  };

  const getOpacity = (feature: Feature) => {
    if (selectedFeatureId && selectedFeatureId !== feature.id) return 0.4;
    return 1;
  };

  const handleMapClick = (e: React.MouseEvent) => {
    if (isAddingAnnotation && svgRef.current) {
      const t = d3.zoomTransform(svgRef.current);
      const rect = svgRef.current.getBoundingClientRect();
      const [x, y] = t.invert([e.clientX - rect.left, e.clientY - rect.top]);
      onAddAnnotation({ id: Date.now().toString(), x, y, text: 'New Annotation' });
    } else {
      if (selectedFeatureId) {
        setSelectedFeatureId(null);
        resetView();
      }
    }
  };

  // -- Render --

  return (
    <GlassPanel 
      className={`h-full w-full relative flex flex-col group overflow-hidden transition-colors duration-500`}
      style={{ backgroundColor: mapStyle.backgroundColor }} 
    >
      <div 
        ref={containerRef} 
        className="relative w-full h-full overflow-hidden bg-transparent"
      >

        {/* --- Top Left: Search Card --- */}
        <div className="absolute top-4 left-4 z-30 w-72">
           <div className={`
              relative flex items-center bg-white rounded-lg shadow-xl transition-all duration-300
              ${isSearchActive ? 'rounded-b-none' : ''}
           `}>
              <div className="pl-3 text-slate-400"><Search size={18}/></div>
              <input 
                 type="text" 
                 className="w-full bg-transparent border-none p-3 text-sm text-slate-800 focus:outline-none placeholder-slate-400"
                 placeholder="Search Google Maps..."
                 value={searchQuery}
                 onChange={handleSearchInput}
                 onFocus={() => searchQuery.length > 1 && setIsSearchActive(true)}
              />
              {searchQuery && (
                <button onClick={() => { setSearchQuery(''); setIsSearchActive(false); }} className="p-2 text-slate-400 hover:text-slate-600">
                  <X size={16} />
                </button>
              )}
           </div>

           {/* Autocomplete Results */}
           {isSearchActive && searchResults.length > 0 && (
             <div className="absolute top-full left-0 w-full bg-white rounded-b-lg shadow-xl overflow-hidden border-t border-slate-100">
                {searchResults.map(feature => (
                  <button
                    key={feature.id}
                    onClick={() => selectSearchResult(feature)}
                    className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700 transition-colors"
                  >
                    <span className="text-lg">{getFlagEmoji(feature.id) || '🏳️'}</span>
                    {feature.properties.name}
                  </button>
                ))}
             </div>
           )}
        </div>

        {/* --- Top Right: Projection & Data --- */}
        <div className="absolute top-4 right-4 z-30 flex flex-col gap-3 items-end">
           {/* Projection Toggle */}
           <div className="bg-white rounded-lg shadow-lg p-1 flex gap-1">
               {(['mercator', 'equalEarth', 'orthographic'] as ProjectionType[]).map(pt => (
                 <button
                   key={pt}
                   onClick={() => setProjectionType(pt)}
                   className={`p-2 rounded transition-all ${projectionType === pt ? 'bg-slate-100 text-primary' : 'text-slate-400 hover:text-slate-600'}`}
                   title={pt}
                 >
                   {pt === 'mercator' ? <MapIcon size={18}/> : pt === 'equalEarth' ? <Layers size={18}/> : <Globe size={18}/>}
                 </button>
               ))}
           </div>

           {/* Data Badge */}
           {mapData && (
              <div className="bg-white rounded-lg shadow-lg px-3 py-2 flex items-center gap-3 animate-in fade-in slide-in-from-right-4">
                 <div className="text-xs font-bold text-slate-700 uppercase tracking-wider flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-accent animate-pulse" />
                    {mapData.metric}
                 </div>
                 <button onClick={() => setMapData(null)} className="text-slate-400 hover:text-red-500 transition-colors">
                   <X size={14} />
                 </button>
              </div>
           )}

           {!mapData && (
             <button 
               onClick={() => setMapData(SAMPLE_DATASET)}
               className="bg-white hover:bg-slate-50 text-primary font-semibold text-xs py-2 px-3 rounded-lg shadow-lg flex items-center gap-2 transition-all"
             >
               <Database size={14} /> Load Demo Data
             </button>
           )}
        </div>


        {/* --- Main SVG Map --- */}
        {loading ? (
           <div className="absolute inset-0 flex items-center justify-center">
             <div className="flex flex-col items-center gap-4">
               <div className="w-16 h-16 border-4 border-slate-700 border-t-accent rounded-full animate-spin" />
               <span className="text-slate-500 font-mono text-sm animate-pulse">LOADING WORLD GEOMETRY...</span>
             </div>
           </div>
        ) : (
          <svg 
            ref={svgRef}
            width="100%" height="100%"
            className={`w-full h-full ${isAddingAnnotation ? 'cursor-crosshair' : 'cursor-grab active:cursor-grabbing'} outline-none`}
            onClick={handleMapClick}
            onMouseLeave={() => { setTooltip(prev => ({ ...prev, visible: false })); setHoveredFeature(null); }}
          >
             <defs>
               <filter id="shadow" x="-50%" y="-50%" width="200%" height="200%">
                 <feDropShadow dx="0" dy="2" stdDeviation="3" floodColor="#000" floodOpacity="0.3"/>
               </filter>
             </defs>

             <g ref={gRef}>
                {geoData.map((feature) => {
                  const isSelected = selectedFeatureId === feature.id;
                  return (
                    <path
                      key={feature.id}
                      d={pathGenerator(feature) || ''}
                      fill={getFill(feature)}
                      fillOpacity={getOpacity(feature)}
                      stroke={isSelected ? '#fff' : mapStyle.borderColor}
                      strokeWidth={isSelected ? 1.5 : mapStyle.showBorders ? mapStyle.borderWidth : 0}
                      vectorEffect="non-scaling-stroke" 
                      className="transition-all duration-300 ease-out"
                      style={{ filter: isSelected || hoveredFeature?.id === feature.id ? 'url(#shadow)' : 'none' }}
                      onMouseEnter={(e) => {
                         setHoveredFeature(feature);
                         const rect = containerRef.current?.getBoundingClientRect();
                         if (rect) {
                           setTooltip({ visible: true, x: e.clientX - rect.left, y: e.clientY - rect.top, content: '' });
                         }
                      }}
                      onMouseMove={(e) => {
                        const rect = containerRef.current?.getBoundingClientRect();
                         if (rect) {
                           setTooltip(prev => ({ ...prev, x: e.clientX - rect.left, y: e.clientY - rect.top }));
                         }
                      }}
                      onDoubleClick={(e) => {
                        e.stopPropagation();
                        focusOnFeature(feature);
                      }}
                      onClick={(e) => {
                        if (!isAddingAnnotation) {
                          e.stopPropagation();
                          focusOnFeature(feature);
                        }
                      }}
                    />
                  );
                })}

                {/* Labels */}
                {labelSettings.showLabels && geoData.map(feature => {
                   const centroid = pathGenerator.centroid(feature);
                   const area = pathGenerator.area(feature);
                   const isVisible = (area * transform.k > 600) || (transform.k > 4); 
                   if (!centroid || isNaN(centroid[0]) || (!isVisible && !labelSettings.smartLabels)) return null;
                   return (
                     <text
                        key={`label-${feature.id}`}
                        x={centroid[0]}
                        y={centroid[1]}
                        textAnchor="middle"
                        dy=".35em"
                        className="pointer-events-none select-none drop-shadow-md transition-opacity duration-500"
                        style={{
                          fill: labelSettings.color,
                          fontFamily: labelSettings.fontFamily,
                          fontSize: `${labelSettings.fontSize / transform.k}px`, 
                          opacity: isVisible || hoveredFeature?.id === feature.id ? 1 : 0
                        }}
                     >
                       {feature.properties.name}
                     </text>
                   );
                })}

                {/* Annotations */}
                {annotations.map((ann) => (
                    <foreignObject
                      key={ann.id}
                      x={ann.x}
                      y={ann.y}
                      width={1} height={1} 
                      className="overflow-visible"
                    >
                       <div 
                         className="absolute transform -translate-x-1/2 -translate-y-1/2 group"
                         onMouseDown={(e) => { e.stopPropagation(); setDraggingAnnotationId(ann.id); }}
                       >
                          {editingAnnotationId === ann.id ? (
                             <textarea
                               autoFocus
                               defaultValue={ann.text}
                               onBlur={(e) => { onUpdateAnnotation(ann.id, e.target.value); setEditingAnnotationId(null); }}
                               onMouseDown={(e) => e.stopPropagation()}
                               className="bg-slate-800/90 text-white p-2 rounded border border-accent min-w-[150px]"
                               style={{ fontSize: `${14 / transform.k}px`, transform: `scale(${1/transform.k})` }}
                             />
                          ) : (
                             <div 
                               onDoubleClick={(e) => { e.stopPropagation(); setEditingAnnotationId(ann.id); }}
                               className="cursor-move px-2 py-1 rounded hover:bg-black/30 border border-transparent hover:border-white/20 transition-all"
                             >
                                <div style={{ color: 'white', textShadow: '0 2px 4px rgba(0,0,0,0.5)', fontSize: `${16 / transform.k}px`, whiteSpace: 'nowrap' }}>
                                  {ann.text}
                                </div>
                                <button 
                                  onClick={(e) => { e.stopPropagation(); onDeleteAnnotation(ann.id); }}
                                  className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                                  style={{ transform: `scale(${1/transform.k})` }}
                                >
                                  <X size={10} />
                                </button>
                             </div>
                          )}
                       </div>
                    </foreignObject>
                ))}
             </g>
          </svg>
        )}

        {/* --- Tooltip --- */}
        <div 
          className="absolute z-50 pointer-events-none transition-all duration-100 ease-out"
          style={{ 
             left: tooltip.x, top: tooltip.y, 
             transform: `translate(-50%, -130%)`,
             opacity: tooltip.visible ? 1 : 0
          }}
        >
          {hoveredFeature && (
            <div className="bg-white rounded shadow-2xl p-3 min-w-[140px] text-slate-800 relative">
               <div className="flex items-center gap-2 mb-1 pb-1 border-b border-slate-100">
                  <span className="text-xl leading-none">{getFlagEmoji(hoveredFeature.id) || '🏳️'}</span>
                  <span className="font-bold text-sm">{hoveredFeature.properties.name}</span>
               </div>

               {mapData && mapData.values[hoveredFeature.id] !== undefined ? (
                  <div className="flex justify-between items-center text-xs">
                     <span className="text-slate-500">{mapData.metric}:</span>
                     <span className="font-mono font-bold text-primary">{mapData.values[hoveredFeature.id]}</span>
                  </div>
               ) : (
                  <div className="text-[10px] text-slate-400 italic">No data available</div>
               )}

               <div className="absolute bottom-[-6px] left-1/2 -translate-x-1/2 w-3 h-3 bg-white rotate-45 shadow-sm" />
            </div>
          )}
        </div>

        {/* --- Bottom Right: Google-style Controls --- */}
        <div className="absolute bottom-6 right-6 flex flex-col gap-2 z-30">
           <div className="flex flex-col bg-white rounded-lg shadow-xl overflow-hidden">
              <button onClick={() => handleZoom(1.4)} className="p-3 hover:bg-slate-50 active:bg-slate-100 border-b border-slate-100 text-slate-600 transition-colors">
                <Plus size={20} />
              </button>
              <button onClick={() => handleZoom(0.7)} className="p-3 hover:bg-slate-50 active:bg-slate-100 text-slate-600 transition-colors">
                <Minus size={20} />
              </button>
           </div>
           <button onClick={resetView} className="bg-white p-3 rounded-lg shadow-xl hover:bg-slate-50 active:bg-slate-100 text-slate-600 transition-colors" title="Reset">
             <Navigation size={20} className={transform.k > 1 ? "text-primary fill-primary/20" : ""} />
           </button>
           <button onClick={toggleFullscreen} className="bg-white p-3 rounded-lg shadow-xl hover:bg-slate-50 active:bg-slate-100 text-slate-600 transition-colors">
             {isFullscreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
           </button>
        </div>

        {/* --- Bottom Left: Minimap --- */}
        <div className="absolute bottom-6 left-6 z-20 hidden md:block">
           <div className="bg-white/90 backdrop-blur border-4 border-white rounded-lg shadow-2xl overflow-hidden w-[120px] h-[120px] relative transition-transform hover:scale-105 duration-300">
               <svg width="100%" height="100%" viewBox={`0 0 ${minimapProps.size} ${minimapProps.size}`}>
                  <path d={minimapProps.path(meshData) || ''} fill="#cbd5e1" />
                  <rect
                    x={-transform.x / transform.k / (dimensions.width / minimapProps.size)}
                    y={-transform.y / transform.k / (dimensions.width / minimapProps.size)}
                    width={dimensions.width / transform.k / (dimensions.width / minimapProps.size)}
                    height={dimensions.height / transform.k / (dimensions.width / minimapProps.size)}
                    fill="none" stroke="#0ea5e9" strokeWidth={1.5}
                  />
               </svg>
           </div>
        </div>

        {/* --- Bottom Center: Legend --- */}
        {mapData && (
           <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-20 bg-white/90 backdrop-blur rounded-full px-4 py-2 shadow-xl flex items-center gap-3 border border-white">
              <span className="text-[10px] font-bold text-slate-500">{d3.min(Object.values(mapData.values))}</span>
              <div className="w-32 h-2 rounded-full" style={{ background: `linear-gradient(to right, ${PALETTES[mapStyle.palette].join(', ')})` }} />
              <span className="text-[10px] font-bold text-slate-500">{d3.max(Object.values(mapData.values))}</span>
           </div>
        )}

      </div>
    </GlassPanel>
  );
};

To implement the Template Gallery, I will create a new component `TemplateGallery.tsx`, update the `types.ts` with template definitions, and integrate it into `App.tsx` and `Sidebar.tsx`.

### **Specification**

1.  **Shared Types (`types.ts`)**:
    *   Add `MapTemplate` interface.
    *   Define `PRESET_TEMPLATES` containing 6 diverse templates (Population, Economy, Climate, etc.) with pre-configured style, data, and title settings.

2.  **Template Gallery Component (`components/TemplateGallery.tsx`)**:
    *   **UI**: A large modal centered on screen using `GlassPanel`.
    *   **State**: Manage `searchQuery`, `activeTab` (All/Favorites/My Templates), `favorites` (IDs stored in LocalStorage), and `customTemplates` (stored in LocalStorage).
    *   **Features**:
        *   **Filtering**: Filter presets by search text and active tab.
        *   **Cards**: Display template name, description, "Popular" badge, and a visual preview (CSS gradient).
        *   **Actions**: "Use Template" (calls parent prop), "Star/Unstar" (toggles LocalStorage).
        *   **Save Current**: Input form to save the current map state as a new personal template.

3.  **App Integration (`App.tsx`)**:
    *   Manage `isGalleryOpen` state.
    *   Implement `handleLoadTemplate` to bulk-update `mapStyle`, `mapData`, and `titleSettings`.
    *   Implement `handleSaveTemplate` to receive a new template object from the gallery component (or handle logic there).

4.  **Entry Point (`components/Sidebar.tsx`)**:
    *   Add a "Browse Templates" button in the header area.
