## components/ExportModal.tsx

New component handling PNG/SVG/JSON generation and sharing options.

```tsx
import React, { useState } from 'react';
import { 
  Download, Share2, Printer, X, Image as ImageIcon, FileCode, FileJson, 
  Check, Copy, Twitter, Facebook, Linkedin, Code, Loader2
} from 'lucide-react';
import { GlassPanel } from './GlassPanel';
import { MapStyle, MapDataState, TitleSettings } from '../types';

interface ExportModalProps {
  isOpen: boolean;
  onClose: () => void;
  config: {
    style: MapStyle;
    data: MapDataState | null;
    titleSettings: TitleSettings;
  };
}

export const ExportModal: React.FC<ExportModalProps> = ({ isOpen, onClose, config }) => {
  const [activeTab, setActiveTab] = useState<'export' | 'share' | 'print'>('export');
  const [format, setFormat] = useState<'png' | 'svg' | 'json'>('png');
  const [resolution, setResolution] = useState<'720' | '1080' | '4k'>('1080');
  const [transparentBg, setTransparentBg] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [copied, setCopied] = useState(false);

  if (!isOpen) return null;

  // -- Export Logic --

  const handleDownload = async () => {
    setIsExporting(true);

    // Simulate delay for effect & async operations
    setTimeout(async () => {
      try {
        if (format === 'json') {
          exportJSON();
        } else if (format === 'svg') {
          exportSVG();
        } else if (format === 'png') {
          await exportPNG();
        }
      } catch (e) {
        console.error("Export failed", e);
      }
      setIsExporting(false);
    }, 800);
  };

  const exportJSON = () => {
    const dataStr = JSON.stringify(config, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    triggerDownload(dataUri, 'mapviz-config.json');
  };

  const exportSVG = () => {
    const svgEl = document.getElementById('map-export-target') as any;
    if (!svgEl) return;

    // Clone to manipulate properties for export without affecting view
    const clone = svgEl.cloneNode(true);

    // Ensure background color is part of the SVG if not transparent
    if (!transparentBg) {
      clone.style.backgroundColor = config.style.backgroundColor;
    } else {
      clone.style.backgroundColor = 'transparent';
    }

    const serializer = new XMLSerializer();
    let source = serializer.serializeToString(clone);

    // Add namespace
    if(!source.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)){
        source = source.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
    }
    if(!source.match(/^<svg[^>]+xmlns:xlink/)){
        source = source.replace(/^<svg/, '<svg xmlns:xlink="http://www.w3.org/1999/xlink"');
    }

    const url = "data:image/svg+xml;charset=utf-8,"+encodeURIComponent(source);
    triggerDownload(url, 'mapviz-export.svg');
  };

  const exportPNG = () => {
    return new Promise<void>((resolve) => {
      const svgEl = document.getElementById('map-export-target') as any;
      if (!svgEl) { resolve(); return; }

      const scaleMap = { '720': 1, '1080': 2, '4k': 4 };
      const scale = scaleMap[resolution];

      const { width, height } = svgEl.getBoundingClientRect();
      const canvas = document.createElement('canvas');
      canvas.width = width * scale;
      canvas.height = height * scale;
      const ctx = canvas.getContext('2d');
      if (!ctx) { resolve(); return; }

      // Draw background if not transparent
      if (!transparentBg) {
        ctx.fillStyle = config.style.backgroundColor;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }

      // Serialize SVG
      const serializer = new XMLSerializer();
      const svgString = serializer.serializeToString(svgEl);
      const img = new Image();

      // Handle special characters/fonts in SVG for data URI
      const svgBlob = new Blob([svgString], {type: 'image/svg+xml;charset=utf-8'});
      const url = URL.createObjectURL(svgBlob);

      img.onload = () => {
        ctx.drawImage(img, 0, 0, width * scale, height * scale);

        // Convert to PNG
        const pngUrl = canvas.toDataURL('image/png');
        triggerDownload(pngUrl, `mapviz-export-${resolution}.png`);

        URL.revokeObjectURL(url);
        resolve();
      };

      img.src = url;
    });
  };

  const triggerDownload = (url: string, filename: string) => {
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleCopyLink = () => {
    // Mock URL
    navigator.clipboard.writeText("https://mapviz.ai/share/v/8f92a3");
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
      <GlassPanel className="w-full max-w-2xl bg-[#0b1121]/95 relative overflow-hidden flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="p-5 border-b border-white/5 flex items-center justify-between">
           <h2 className="text-xl font-bold text-white flex items-center gap-2">
             <Download className="text-accent" size={24} />
             Export & Share
           </h2>
           <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
             <X size={20} className="text-slate-400" />
           </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-white/5">
           <button 
             onClick={() => setActiveTab('export')}
             className={`flex-1 py-4 text-sm font-medium transition-all relative ${activeTab === 'export' ? 'text-white' : 'text-slate-500 hover:text-slate-300'}`}
           >
             <div className="flex items-center justify-center gap-2">
                <ImageIcon size={16} /> Export Image
             </div>
             {activeTab === 'export' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-accent shadow-[0_0_10px_rgba(6,182,212,0.5)]" />}
           </button>
           <button 
             onClick={() => setActiveTab('share')}
             className={`flex-1 py-4 text-sm font-medium transition-all relative ${activeTab === 'share' ? 'text-white' : 'text-slate-500 hover:text-slate-300'}`}
           >
             <div className="flex items-center justify-center gap-2">
                <Share2 size={16} /> Share Link
             </div>
             {activeTab === 'share' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-accent shadow-[0_0_10px_rgba(6,182,212,0.5)]" />}
           </button>
           <button 
             onClick={() => setActiveTab('print')}
             className={`flex-1 py-4 text-sm font-medium transition-all relative ${activeTab === 'print' ? 'text-white' : 'text-slate-500 hover:text-slate-300'}`}
           >
             <div className="flex items-center justify-center gap-2">
                <Printer size={16} /> Print
             </div>
             {activeTab === 'print' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-accent shadow-[0_0_10px_rgba(6,182,212,0.5)]" />}
           </button>
        </div>

        {/* Content */}
        <div className="p-6 overflow-y-auto">

           {/* --- EXPORT TAB --- */}
           {activeTab === 'export' && (
             <div className="space-y-6">

                {/* Format Selection */}
                <div className="grid grid-cols-3 gap-4">
                   <button 
                     onClick={() => setFormat('png')}
                     className={`p-4 rounded-xl border flex flex-col items-center gap-3 transition-all ${format === 'png' ? 'bg-accent/10 border-accent text-white' : 'bg-slate-900 border-white/10 text-slate-400 hover:bg-white/5'}`}
                   >
                      <ImageIcon size={24} className={format === 'png' ? 'text-accent' : ''} />
                      <span className="font-bold text-sm">PNG Image</span>
                   </button>
                   <button 
                     onClick={() => setFormat('svg')}
                     className={`p-4 rounded-xl border flex flex-col items-center gap-3 transition-all ${format === 'svg' ? 'bg-accent/10 border-accent text-white' : 'bg-slate-900 border-white/10 text-slate-400 hover:bg-white/5'}`}
                   >
                      <FileCode size={24} className={format === 'svg' ? 'text-accent' : ''} />
                      <span className="font-bold text-sm">SVG Vector</span>
                   </button>
                   <button 
                     onClick={() => setFormat('json')}
                     className={`p-4 rounded-xl border flex flex-col items-center gap-3 transition-all ${format === 'json' ? 'bg-accent/10 border-accent text-white' : 'bg-slate-900 border-white/10 text-slate-400 hover:bg-white/5'}`}
                   >
                      <FileJson size={24} className={format === 'json' ? 'text-accent' : ''} />
                      <span className="font-bold text-sm">JSON Data</span>
                   </button>
                </div>

                {/* Settings */}
                <div className="space-y-4">
                   {format === 'png' && (
                     <div className="space-y-2">
                        <label className="text-xs font-bold text-slate-400 uppercase">Resolution</label>
                        <select 
                          value={resolution}
                          onChange={(e) => setResolution(e.target.value as any)}
                          className="w-full bg-slate-900 border border-white/10 rounded-lg p-3 text-sm text-white focus:outline-none focus:border-accent"
                        >
                           <option value="720">Web (720p)</option>
                           <option value="1080">Standard (1080p)</option>
                           <option value="4k">Print / High Res (4K)</option>
                        </select>
                     </div>
                   )}

                   {(format === 'png' || format === 'svg') && (
                     <div className="flex items-center justify-between p-3 rounded-lg bg-slate-900/50 border border-white/5">
                        <span className="text-sm text-slate-300">Transparent Background</span>
